// // This module implements a 16-bit DRAM cell with read and write operations.
// It has a 16-bit input data bus, a single 16-bit output data bus,
// and control signals for reading and writing.
// The read operation outputs the stored value,
// while the write operation stores the input value.
// The control signals are defined as follows:
// write_enable (active low) for writing data,
// and read_enable (active low) for reading data.
// The cell holds the last written value until a new write occurs.
module dram_cell(
    input clk,
    input [15:0] data_in,
    input write_enable,
    input read_enable,
    output reg [15:0] data_out
);
    reg [15:0] storage;

    always @(posedge clk) begin
        if (write_enable) begin
            storage <= data_in;
        end
    end

    always @(posedge clk) begin
        if (read_enable) begin
            data_out <= storage;
        end
    end
endmodule

